// Node 7 — Validate & Enforce Safety (v5 - Qty-first, Backward Compatible)
// Mode: Run Once for All Items
// Output: [{ json: { decision, commentary, agentDecision, orders, metrics, warnings, ctx } }]

// -------------------- HELPERS --------------------
function isObj(x) {
  return x && typeof x === "object" && !Array.isArray(x);
}

function safeJsonParse(s) {
  try { return JSON.parse(s); } catch { return null; }
}

function toNumOrNull(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function toBool(v, dflt = false) {
  if (typeof v === "boolean") return v;
  if (typeof v === "number") return v !== 0;
  const s = String(v ?? "").trim().toLowerCase();
  if (!s) return dflt;
  if (["1", "true", "yes", "y", "on", "enabled"].includes(s)) return true;
  if (["0", "false", "no", "n", "off", "disabled"].includes(s)) return false;
  return dflt;
}

function clampText(s, n) {
  return String(s ?? "").replace(/\s+/g, " ").trim().slice(0, n);
}

function normSymbol(v) {
  return String(v ?? "").trim();
}

function normAssetClass(v, symbol) {
  const raw = String(v ?? "").trim().toUpperCase();
  if (raw === "FX" || raw === "FOREX") return "FX";
  if (raw === "CRYPTO") return "CRYPTO";
  if (raw === "EQUITY" || raw === "STOCK" || raw === "ETF") return "EQUITY";
  const s = String(symbol ?? "").toUpperCase();
  if (s.startsWith("FX:") || s.endsWith("=X")) return "FX";
  return "EQUITY";
}

function fxSymbolInternal(symbol) {
  const s = String(symbol ?? "").toUpperCase();
  if (s.startsWith("FX:")) return s;
  const pair = s.replace("=X", "").replace("/", "").replace(/[^A-Z]/g, "").slice(0, 6);
  return pair.length === 6 ? `FX:${pair}` : s;
}

function fxSymbolYahoo(symbol) {
  const s = String(symbol ?? "").toUpperCase();
  if (s.endsWith("=X")) return s;
  const pair = s.replace("FX:", "").replace("/", "").replace(/[^A-Z]/g, "").slice(0, 6);
  return pair.length === 6 ? `${pair}=X` : s;
}

function normalizeAgentActionsForFx(agentDecision) {
  if (!Array.isArray(agentDecision?.actions)) return agentDecision;

  const next = [];
  for (const raw of agentDecision.actions) {
    const a = isObj(raw) ? deepClone(raw) : {};
    const sym = normSymbol(a.symbol);
    const assetClass = normAssetClass(a.assetClass ?? a.asset_class, sym);
    const actIn = String(a.action ?? "").toUpperCase();

    a.assetClass = assetClass;
    a.asset_class = undefined;

    if (assetClass === "FX") {
      let fxAction = actIn;
      if (["OPEN", "INCREASE", "BUY", "PROPOSE_OPEN"].includes(actIn)) fxAction = "PROPOSE_OPEN";
      else if (["DECREASE", "CLOSE", "SELL", "PROPOSE_CLOSE"].includes(actIn)) fxAction = "PROPOSE_CLOSE";
      else if (!["WATCH", "HOLD"].includes(actIn)) fxAction = "WATCH";

      a.action = fxAction;
      a.symbol_internal = fxSymbolInternal(sym);
      a.symbol_yahoo = fxSymbolYahoo(sym);
      a.execution_required = false;
      a.needs_risk_approval = true;

      if (!Array.isArray(a.dependencies)) {
        const deps = a.dependencies || {};
        const list = [];
        if (deps.needPrice) list.push("PRICE");
        if (deps.needNote) list.push("NOTE");
        if (deps.needNews) list.push("NEWS");
        if (deps.needTechnical) list.push("TECHNICAL");
        if (deps.needConsensus) list.push("CONSENSUS");
        a.dependencies = list;
      }
      if (!a.dependencies.includes("AG5_RISK_APPROVAL")) a.dependencies.push("AG5_RISK_APPROVAL");
      if (!a.dependencies.includes("AG6_EXECUTION")) a.dependencies.push("AG6_EXECUTION");

      if (!isObj(a.proposed_position)) {
        a.proposed_position = {
          direction: fxAction === "PROPOSE_OPEN" ? "LONG" : (fxAction === "PROPOSE_CLOSE" ? "NEUTRAL" : "NEUTRAL"),
          conviction: Number.isFinite(Number(a.confidence)) ? Number(a.confidence) : null,
        };
      }
    } else {
      if (a.execution_required === undefined) a.execution_required = null;
      if (a.needs_risk_approval === undefined) a.needs_risk_approval = null;
    }

    next.push(a);
  }

  agentDecision.actions = next;
  return agentDecision;
}

function appendFxPairProposals(agentDecision, input) {
  const fxPairs = Array.isArray(input?.fx_pairs) ? input.fx_pairs : [];
  if (!fxPairs.length) return agentDecision;

  const existing = new Set();
  for (const a of agentDecision.actions || []) {
    const ac = normAssetClass(a?.assetClass ?? a?.asset_class, a?.symbol);
    if (ac !== "FX") continue;
    const sym = fxSymbolInternal(a?.symbol_internal || a?.symbol || "");
    if (sym) existing.add(sym);
  }

  for (const p of fxPairs) {
    const symbolInternal = fxSymbolInternal(p?.symbol_internal || p?.pair || p?.symbol || "");
    if (!symbolInternal || existing.has(symbolInternal)) continue;

    const bias = String(p?.directional_bias ?? "NEUTRAL").toUpperCase();
    const action = bias === "BUY_BASE" ? "PROPOSE_OPEN" : (bias === "SELL_BASE" ? "PROPOSE_CLOSE" : "WATCH");
    const confRaw = Number(p?.confidence);
    const confidence = Number.isFinite(confRaw) ? Math.max(0, Math.min(100, Math.round(confRaw))) : null;
    const urgent = toBool(p?.urgent_event_window, false);

    (agentDecision.actions = Array.isArray(agentDecision.actions) ? agentDecision.actions : []).push({
      symbol: symbolInternal,
      symbol_internal: symbolInternal,
      symbol_yahoo: fxSymbolYahoo(symbolInternal),
      assetClass: "FX",
      action,
      priority: action === "WATCH" ? 3 : 2,
      confidence,
      horizonDays: action === "WATCH" ? null : 5,
      targetWeightPct: null,
      targetQty: null,
      rationale: clampText(p?.rationale || `${symbolInternal} ${bias}`, 300),
      entryPlan: { orderType: null, limitPrice: null, timeInForce: null },
      riskPlan: { stopLossPct: null, takeProfitPct: null, maxLossEUR: null },
      dependencies: ["AG5_RISK_APPROVAL", "AG6_EXECUTION"],
      execution_required: false,
      needs_risk_approval: true,
      proposed_position: {
        direction: action === "PROPOSE_OPEN" ? "LONG" : (action === "PROPOSE_CLOSE" ? "NEUTRAL" : "NEUTRAL"),
        conviction: confidence,
      },
      nextReviewDays: urgent ? 1 : 3,
    });
    existing.add(symbolInternal);
  }

  return agentDecision;
}

function uniq(arr) {
  return Array.from(new Set((arr || []).filter(Boolean)));
}

function deepClone(obj) {
  try { return JSON.parse(JSON.stringify(obj)); } catch { return obj; }
}

function pickFirstRelevantInput(all) {
  for (const it of all) {
    const j = it?.json ?? {};
    if (j.portfolioSummary || j.portfolioRows || j.ctx?.portfolioSummary) return j;
  }
  return all[0]?.json ?? {};
}

function extractNewsItems(input) {
  const candidates = [
    input?.market?.newsItems,
    input?.market?.marketNewsPack?.newsItems,
    input?.market?.marketNewsPack?.topItems,
    input?.market?.marketNewsPack?.items,
    input?.marketNewsPack?.newsItems,
    input?.marketNewsPack?.topItems,
    input?.marketNewsPack?.items,
    input?.newsItems,
    input?.news,
    input?.market?.news,
  ];
  for (const c of candidates) {
    if (Array.isArray(c) && c.length) return c;
  }
  return [];
}

function getPortfolioPositionsSymbols(portfolioSummary) {
  const pos = Array.isArray(portfolioSummary?.positions) ? portfolioSummary.positions : [];
  return uniq(
    pos
      .map((p) => normSymbol(p.Symbol ?? p.symbol))
      .filter((s) => s && s !== "CASH_EUR" && s !== "__META__")
  );
}

function buildPricesFallbackFromPortfolio(portfolioSummary) {
  const pricesFallback = {};
  const posArr = Array.isArray(portfolioSummary?.positions) ? portfolioSummary.positions : [];

  for (const p of posArr) {
    const s = normSymbol(p.Symbol ?? p.symbol);
    if (!s || s === "CASH_EUR" || s === "__META__") continue;

    let last = Number(p.LastPrice ?? NaN);
    if (!Number.isFinite(last) || last <= 0) {
      const q = Number(p.Quantity ?? NaN);
      const mv = Number(p.MarketValue ?? NaN);
      if (Number.isFinite(q) && q > 0 && Number.isFinite(mv)) last = mv / q;
    }

    if (Number.isFinite(last) && last > 0) {
      pricesFallback[s] = {
        lastPrice: last,
        source: "portfolio_lastPrice",
        ts: String(p.UpdatedAt ?? ""),
        stale: false,
      };
    }
  }
  return pricesFallback;
}

// -------------------- AGENT DECISION PARSING --------------------
function extractAgentDecisionObject(input) {
  // 1) Already a structured object at input.output
  if (
    isObj(input.output) &&
    (Array.isArray(input.output.actions) || isObj(input.output.portfolioPlan) || isObj(input.output.decisionMeta))
  ) {
    return { ...input.output, _parseStatus: "OK_OBJECT_OUTPUT" };
  }

  // 2) Already a structured object at input.agentDecision
  if (isObj(input.agentDecision)) {
    return { ...input.agentDecision, _parseStatus: "OK_AGENTDECISION" };
  }

  // 3) Information Extractor can return actions[] directly
  if (
    Array.isArray(input.output) &&
    input.output.length > 0 &&
    input.output.every((x) => isObj(x) && String(x.action ?? "").length)
  ) {
    return {
      actions: input.output,
      dataCaveats: [],
      backfillRequests: [],
      _parseStatus: "OK_ACTIONS_ARRAY_OUTPUT",
    };
  }

  // 4) LangChain / OpenAI-ish message envelopes
  const msg0 = Array.isArray(input.output) ? input.output[0] : null;
  const content0 = msg0 && Array.isArray(msg0.content) ? msg0.content[0] : null;
  let decisionRaw = content0?.text ?? content0?.text?.text ?? null;

  if (isObj(decisionRaw)) return { ...decisionRaw, _parseStatus: "OK_OPENAI_OBJECT" };

  if (typeof decisionRaw === "string") {
    const parsed = safeJsonParse(decisionRaw);
    if (isObj(parsed)) return { ...parsed, _parseStatus: "OK_OPENAI_TEXT_JSON" };
    return { _rawText: decisionRaw, _parseStatus: "TEXT_NOT_JSON" };
  }

  if (decisionRaw == null) {
    return { _parseStatus: "MISSING_DECISION", _why: "No decision payload found." };
  }

  return { _rawValue: decisionRaw, _parseStatus: "UNEXPECTED_TYPE" };
}

function coerceAgentDecisionToExpectedShape(agentDecision) {
  if (!isObj(agentDecision)) {
    return { _parseStatus: "NOT_OBJECT", actions: [], dataCaveats: [], backfillRequests: [] };
  }
  const d = deepClone(agentDecision);
  if (!Array.isArray(d.actions)) d.actions = [];
  if (!Array.isArray(d.dataCaveats)) d.dataCaveats = [];
  if (!Array.isArray(d.backfillRequests)) d.backfillRequests = [];
  return d;
}

// -------------------- PORTFOLIO/PRICES --------------------
function computeTotalPortfolioValueEUR(portfolioSummary, prices) {
  const explicit = Number(portfolioSummary?.totalPortfolioValueEUR ?? portfolioSummary?.totalValueEUR ?? NaN);
  if (Number.isFinite(explicit) && explicit > 0) return explicit;

  const cash = Number(portfolioSummary?.cashEUR ?? 0);
  const posArr = Array.isArray(portfolioSummary?.positions) ? portfolioSummary.positions : [];
  let equity = 0;

  for (const p of posArr) {
    const s = normSymbol(p.Symbol ?? p.symbol);
    if (!s || s === "CASH_EUR" || s === "__META__") continue;

    const q = Number(p.Quantity ?? 0);
    if (!Number.isFinite(q) || q === 0) continue;

    const last = Number(prices?.[s]?.lastPrice ?? p.LastPrice ?? NaN);
    if (Number.isFinite(last) && last > 0) equity += q * last;
    else {
      const mv = Number(p.MarketValue ?? NaN);
      if (Number.isFinite(mv)) equity += mv;
    }
  }
  return cash + equity;
}

function buildHoldingsMap(portfolioSummary, prices) {
  const map = {};
  const posArr = Array.isArray(portfolioSummary?.positions) ? portfolioSummary.positions : [];

  for (const p of posArr) {
    const s = normSymbol(p.Symbol ?? p.symbol);
    if (!s || s === "CASH_EUR" || s === "__META__") continue;

    const qty = Number(p.Quantity ?? 0);
    const last = Number(prices?.[s]?.lastPrice ?? p.LastPrice ?? NaN);

    map[s] = {
      Symbol: s,
      Quantity: Number.isFinite(qty) ? qty : 0,
      LastPrice: Number.isFinite(last) ? last : null,
    };
  }
  return map;
}

// -------------------- ORDER GENERATION (QTY-FIRST) --------------------
function generateOrdersFromActions(agentDecision, portfolioSummary, prices, feesConfig) {
  const warnings = [];
  const ordersSell = [];
  const ordersBuy = [];

  const actions = Array.isArray(agentDecision?.actions) ? agentDecision.actions : [];
  const holdings = buildHoldingsMap(portfolioSummary, prices);

  // Needed for legacy sizing via targetWeightPct
  const totalValue = computeTotalPortfolioValueEUR(portfolioSummary, prices);
  if (!Number.isFinite(totalValue) || totalValue <= 0) {
    warnings.push("PORTFOLIO_VALUE_INVALID: cannot size orders.");
    return { orders: [], warnings };
  }

  // Cash simulation to gate buys
  let cashSim = Number(portfolioSummary?.cashEUR ?? 0);
  const fixed = Number(feesConfig?.orderFeeFixedEUR ?? 0);
  const pct = Number(feesConfig?.orderFeePct ?? 0);

  // Helper: resolve current qty (0 if not held)
  const currentQty = (sym) => {
    const h = holdings[sym];
    const q = Number(h?.Quantity ?? 0);
    return Number.isFinite(q) ? q : 0;
  };

  for (const a of actions) {
    const sym = normSymbol(a?.symbol);
    const act = String(a?.action ?? "").toUpperCase();
    const assetClass = normAssetClass(a?.assetClass ?? a?.asset_class, sym);
    if (!sym) continue;
    if (assetClass === "FX") continue; // AG5/AG6 not in scope: FX stays non-executable.
    if (!["OPEN", "INCREASE", "DECREASE", "CLOSE"].includes(act)) continue;

    const px = Number(prices?.[sym]?.lastPrice ?? NaN);
    if (!Number.isFinite(px) || px <= 0) {
      warnings.push(`SKIP_NO_PRICE:${sym}:${act}`);
      continue;
    }

    const q0 = currentQty(sym);

    const entryPlan = isObj(a?.entryPlan) ? a.entryPlan : {};
    const riskPlan = isObj(a?.riskPlan) ? a.riskPlan : {};

    // --- QTY-FIRST TARGET RESOLUTION (backward compatible) ---
    const targetQtyExplicit = toNumOrNull(a?.targetQty ?? a?.targetQuantity ?? null);
    const targetNotionalExplicit = toNumOrNull(a?.targetNotionalEUR ?? a?.targetNotional ?? null);

    let targetQty = null;

    if (act === "CLOSE") {
      targetQty = 0;
    } else if (targetQtyExplicit != null) {
      targetQty = targetQtyExplicit;
    } else if (targetNotionalExplicit != null) {
      targetQty = targetNotionalExplicit / px;
    } else if (a?.targetWeightPct != null) {
      const targetNotional = (Number(a.targetWeightPct) / 100) * totalValue;
      if (Number.isFinite(targetNotional)) targetQty = targetNotional / px;
    }

    if (targetQty == null || !Number.isFinite(targetQty)) {
      warnings.push(`SKIP_NO_TARGET:${sym}:${act}`);
      continue;
    }

    // Orders are integer quantities by design
    // - SELL: ceil to ensure reaching targetQty or below
    // - BUY : floor to avoid cash overshoot
    if (act === "DECREASE" || act === "CLOSE") {
      if (q0 <= 0) continue;

      const rawSell = q0 - targetQty;
      const qtyToSell = Math.min(q0, Math.ceil(rawSell));

      if (qtyToSell >= 1) {
        ordersSell.push({
          symbol: sym,
          side: "SELL",
          quantity: qtyToSell,
          price: null,
          rationale: clampText(a?.rationale, 240),
          orderType: String(entryPlan.orderType || "MARKET"),
          limitPrice: toNumOrNull(entryPlan.limitPrice),
          stopLossPct: toNumOrNull(riskPlan.stopLossPct),
          confidence: a?.confidence,
          priority: a?.priority,
        });
      }
    }

    if (act === "OPEN" || act === "INCREASE") {
      const rawBuy = targetQty - q0;
      const qtyToBuy = Math.floor(rawBuy);

      if (qtyToBuy >= 1) {
        ordersBuy.push({
          symbol: sym,
          side: "BUY",
          quantity: qtyToBuy,
          price: null,
          rationale: clampText(a?.rationale, 240),
          orderType: String(entryPlan.orderType || "MARKET"),
          limitPrice: toNumOrNull(entryPlan.limitPrice),
          stopLossPct: toNumOrNull(riskPlan.stopLossPct),
          confidence: a?.confidence,
          priority: a?.priority,
        });
      }
    }
  }

  // Execution simulation: sells first, then buys if cash is sufficient
  const finalOrders = [];

  for (const o of ordersSell) {
    finalOrders.push(o);
    const px = Number(prices?.[o.symbol]?.lastPrice ?? NaN);
    if (Number.isFinite(px) && px > 0) {
      const proceeds = (o.quantity * px) * (1 - pct) - fixed;
      cashSim += proceeds;
    }
  }

  for (const o of ordersBuy) {
    const px = Number(prices?.[o.symbol]?.lastPrice ?? NaN);
    if (Number.isFinite(px) && px > 0) {
      const cost = (o.quantity * px) * (1 + pct) + fixed;
      if (cashSim >= cost) {
        finalOrders.push(o);
        cashSim -= cost;
      } else {
        warnings.push(`SKIP_INSUFFICIENT_CASH:${o.symbol}`);
      }
    }
  }

  return { orders: finalOrders, warnings };
}

function estimateFeesEUR(orders, feesConfig, prices) {
  const fixed = Number(feesConfig?.orderFeeFixedEUR ?? 0);
  const pct = Number(feesConfig?.orderFeePct ?? 0);
  let total = 0;

  for (const o of orders) {
    const s = normSymbol(o.symbol);
    const q = Number(o.quantity ?? NaN);
    if (!s || !Number.isFinite(q) || q <= 0) continue;
    const px = Number(o.price ?? prices?.[s]?.lastPrice ?? NaN);
    if (!Number.isFinite(px) || px <= 0) continue;
    total += fixed + pct * (q * px);
  }
  return total;
}

// -------------------- MAIN --------------------
const all = $input.all();
const input = pickFirstRelevantInput(all);

const now = new Date();
const ts = now.toISOString();

const portfolioSummary = input.portfolioSummary ?? input.ctx?.portfolioSummary ?? { cashEUR: 0, positions: [] };
const meta0 = input.meta ?? input.ctx?.meta ?? {};
const config0 = input.config ?? input.ctx?.config ?? {};
const feesConfig = input.feesConfig ?? input.ctx?.feesConfig ?? { orderFeeFixedEUR: 0, orderFeePct: 0 };

const market0 = input.market ?? input.ctx?.market ?? {};
const upstreamPrices = isObj(market0.prices) ? market0.prices : {};
const upstreamNewsItems = extractNewsItems(input);

// Agent decision parsing
let agentDecision = extractAgentDecisionObject(input);
agentDecision = coerceAgentDecisionToExpectedShape(agentDecision);
agentDecision = normalizeAgentActionsForFx(agentDecision);
agentDecision = appendFxPairProposals(agentDecision, input);
agentDecision = normalizeAgentActionsForFx(agentDecision);

// Prices merge (fallback from portfolio)
const pricesFallback = buildPricesFallbackFromPortfolio(portfolioSummary);
const mergedPrices = { ...pricesFallback, ...upstreamPrices };

// --- PATCH : INJECT LIMIT PRICES AS PROXY (only if missing market price) ---
const injectedPrices = [];
if (Array.isArray(agentDecision.actions)) {
  for (const action of agentDecision.actions) {
    const sym = normSymbol(action.symbol);
    const limit = toNumOrNull(action.entryPlan?.limitPrice);
    if (sym && limit && limit > 0) {
      const currentPrice = mergedPrices[sym]?.lastPrice;
      if (!Number.isFinite(Number(currentPrice)) || Number(currentPrice) <= 0) {
        mergedPrices[sym] = { lastPrice: limit, source: "agent_limit_proxy", stale: false };
        injectedPrices.push(sym);
      }
    }
  }
}

// Universe + coverage check
const heldSymbols = getPortfolioPositionsSymbols(portfolioSummary);
const tradeSymbols = uniq(
  (Array.isArray(agentDecision?.actions) ? agentDecision.actions : [])
    .filter((a) => {
      const act = String(a?.action ?? "").toUpperCase();
      const sym = normSymbol(a?.symbol);
      const ac = normAssetClass(a?.assetClass ?? a?.asset_class, sym);
      return ac !== "FX" && ["OPEN", "INCREASE", "DECREASE", "CLOSE"].includes(act);
    })
    .map((a) => normSymbol(a?.symbol))
);

let pricedForRequested = 0;
const missingRequested = [];
for (const s of tradeSymbols) {
  const px = Number(mergedPrices?.[s]?.lastPrice ?? NaN);
  if (Number.isFinite(px) && px > 0) pricedForRequested += 1;
  else missingRequested.push(s);
}

const requestedSymbolsCount = tradeSymbols.length;
const okForTrading = requestedSymbolsCount ? (pricedForRequested === requestedSymbolsCount) : true;
const pricesCoverageRequested = requestedSymbolsCount ? (pricedForRequested / requestedSymbolsCount) : 1;

// Generate orders (qty-first)
let { orders, warnings: orderWarnings } = generateOrdersFromActions(
  agentDecision,
  portfolioSummary,
  mergedPrices,
  feesConfig
);

// Safety veto (hard gate)
const safetyWarnings = [];
if (!okForTrading) {
  if (tradeSymbols.length) {
    safetyWarnings.push(`SAFETY_VETO_MISSING_PRICES:${missingRequested.join(",")}`);
    orders = [];
  }
}

if (injectedPrices.length > 0) {
  safetyWarnings.push(`NOTICE: Used agent limit price as proxy for: ${injectedPrices.join(", ")}`);
}

// Warnings aggregation
const warnings = [];

// Parse problems
if (agentDecision?._parseStatus && !String(agentDecision._parseStatus).startsWith("OK")) {
  warnings.push(`AGENT_DECISION_PARSE:${agentDecision._parseStatus}`);
  if (agentDecision?._why) warnings.push(`AGENT_DECISION_PARSE_WHY:${agentDecision._why}`);
}

// Carry caveats
if (Array.isArray(agentDecision?.dataCaveats)) {
  for (const c of agentDecision.dataCaveats) warnings.push(String(c));
}

// Missing prices for held positions (informational)
for (const s of heldSymbols) {
  const px = Number(mergedPrices?.[s]?.lastPrice ?? NaN);
  if (!Number.isFinite(px) || px <= 0) warnings.push(`MISSING_PRICE_FOR_HELD:${s}`);
}

for (const w of orderWarnings) warnings.push(String(w));
for (const w of safetyWarnings) warnings.push(String(w));

// Metrics
const aiCostEUR = Number(input?.metrics?.aiCostEUR ?? 0);
const expectedFeesEUR = estimateFeesEUR(orders, feesConfig, mergedPrices);

// Decision
const decision = orders.length ? "TRADE" : "NO_TRADE";

// Build ctx for downstream nodes (8 / 8B / Sheets)
const runId =
  String(input?.runId ?? input?.ctx?.run?.runId ?? "").trim() ||
  String(agentDecision?.decisionMeta?.run_id ?? "").trim() ||
  "";

const strategyVersion =
  String(input?.strategyVersion ?? input?.ctx?.run?.strategyVersion ?? input?.config?.strategyVersion ?? "").trim() ||
  String(agentDecision?.decisionMeta?.strategy_version ?? "").trim() ||
  "strategy_v3";

const configVersion =
  String(input?.configVersion ?? input?.ctx?.run?.configVersion ?? input?.config?.configVersion ?? "").trim() ||
  String(agentDecision?.decisionMeta?.config_version ?? "").trim() ||
  "config_v3";

const promptVersion =
  String(input?.promptVersion ?? input?.ctx?.run?.promptVersion ?? "").trim() ||
  String(agentDecision?.decisionMeta?.prompt_version ?? "").trim() ||
  "prompt_v3";

const model =
  String(input?.model ?? input?.ctx?.run?.model ?? "").trim() ||
  String(agentDecision?.decisionMeta?.model ?? "").trim() ||
  "gpt-5.2";

const enableFx = toBool(input?.run?.enable_fx ?? input?.ctx?.run?.enable_fx ?? input?.config?.enable_fx, false);
const universeScope = Array.isArray(input?.run?.universe_scope)
  ? input.run.universe_scope
  : (enableFx ? ["EQUITY", "CRYPTO", "FX"] : ["EQUITY", "CRYPTO"]);
const inputSnapshot = isObj(input?.run?.inputSnapshot) ? deepClone(input.run.inputSnapshot) : {};
if (!Array.isArray(inputSnapshot.universe_scope)) inputSnapshot.universe_scope = universeScope;
if (inputSnapshot.enable_fx === undefined) inputSnapshot.enable_fx = enableFx;

// Data quality object consumed by Node 8B
const dataQuality = {
  okForTrading: !!okForTrading,
  requestedSymbolsCount,
  pricedSymbolsCount: pricedForRequested,
  pricesCoverageRequested, // 0..1
  missingRequested,
  injectedPrices,
};

const ctx = {
  sheetId: input.sheetId ?? input.ctx?.sheetId,
  meta: meta0,
  config: config0,
  feesConfig,
  run: {
    runId,
    timestampParis: ts,
    model,
    strategyVersion,
    configVersion,
    promptVersion,
    enable_fx: enableFx,
    universe_scope: universeScope,
    inputSnapshot,
  },
  portfolioSummary,
  market: {
    prices: mergedPrices,
    newsItems: upstreamNewsItems,
    dataQuality,
  },
};

const cash0 = Number(portfolioSummary?.cashEUR ?? 0);
const actionsCount = Array.isArray(agentDecision?.actions) ? agentDecision.actions.length : 0;
const fxActionsCount = Array.isArray(agentDecision?.actions)
  ? agentDecision.actions.filter((a) => normAssetClass(a?.assetClass ?? a?.asset_class, a?.symbol) === "FX").length
  : 0;
const caveatsCount = Array.isArray(agentDecision?.dataCaveats) ? agentDecision.dataCaveats.length : 0;

const commentary = `PM_DECISION=${decision} | orders=${orders.length} | actions=${actionsCount} | fx_actions=${fxActionsCount} | cash0=${cash0} | caveats=${caveatsCount} | priceCoverage=${Math.round(pricesCoverageRequested * 1000) / 10}%`;

return [
  {
    json: {
      decision,
      commentary,
      agentDecision,
      orders,
      metrics: {
        aiCostEUR: Number.isFinite(aiCostEUR) ? aiCostEUR : 0,
        expectedFeesEUR: Number.isFinite(expectedFeesEUR) ? expectedFeesEUR : 0,
      },
      warnings,
      ctx,
    },
  },
];

// 8 - Build DuckDB Bundle (Portfolio Ledger v2)
// Input: Node 7 output (decision, orders, warnings, ctx, agentDecision, metrics)
// Output: [{ json: { run_id, db_path, bundle, summary } }]

function isObj(x) {
  return x && typeof x === "object" && !Array.isArray(x);
}

function toNum(v, d = null) {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
}

function toInt(v, d = null) {
  const n = toNum(v, d);
  return Number.isFinite(n) ? Math.round(n) : d;
}

function clampText(v, max = 0) {
  const s = String(v ?? "").replace(/\s+/g, " ").trim();
  return max > 0 ? s.slice(0, max) : s;
}

function normSymbol(v) {
  return String(v ?? "").trim().toUpperCase();
}

function uniq(arr) {
  return Array.from(new Set((arr || []).filter(Boolean)));
}

function normPctTo100(v) {
  const n = toNum(v, null);
  if (n == null) return null;
  if (n <= 1) return Math.max(0, Math.min(100, n * 100));
  return Math.max(0, Math.min(100, n));
}

function clamp0100(v) {
  const n = toNum(v, null);
  if (n == null) return null;
  return Math.max(0, Math.min(100, Math.round(n)));
}

function makeId(prefix, ...parts) {
  const tokens = [prefix, ...parts]
    .map((x) => clampText(x, 80).replace(/[^\w.\-:]/g, "_"))
    .filter(Boolean);
  return tokens.join("|");
}

function parseAgentDecision(input) {
  if (isObj(input.agentDecision)) return input.agentDecision;
  if (isObj(input.output)) return input.output;
  return {};
}

function buildRunId(ctxRun, agentDecision, nowIso, executionId) {
  const c1 = clampText(ctxRun?.runId, 96);
  if (c1) return c1;
  const c2 = clampText(agentDecision?.decisionMeta?.run_id, 96);
  if (c2) return c2;
  const stampBase = clampText(ctxRun?.timestampParis, 64) || nowIso;
  const stamp = stampBase.replace(/[-:.TZ]/g, "").slice(0, 14);
  const exec = clampText(executionId, 32).replace(/[^\w.\-:]/g, "_") || "NOEXEC";
  return `RUN_${stamp}_${exec}`;
}

function getOrderActionMap(actions) {
  const out = new Map();
  for (const a of actions || []) {
    const s = normSymbol(a?.symbol);
    if (!s || out.has(s)) continue;
    out.set(s, String(a?.action ?? "").toUpperCase());
  }
  return out;
}

function mapIntent(action, side) {
  const a = String(action || "").toUpperCase();
  if (a === "OPEN") return "OPEN";
  if (a === "INCREASE") return "INCREASE";
  if (a === "DECREASE") return "REDUCE";
  if (a === "CLOSE") return "CLOSE";
  return side === "BUY" ? "OPEN" : "REDUCE";
}

function mapSignal(action) {
  const a = String(action || "").toUpperCase();
  if (a === "OPEN" || a === "INCREASE" || a === "BUY") return "BUY";
  if (a === "DECREASE" || a === "CLOSE" || a === "SELL") return "SELL";
  if (a === "PROPOSE_OPEN") return "PROPOSE_OPEN";
  if (a === "PROPOSE_CLOSE") return "PROPOSE_CLOSE";
  if (a === "WATCH") return "WATCH";
  if (a === "HOLD") return "HOLD";
  return "NEUTRAL";
}

function extractPrice(symbol, order, prices) {
  const pOrder = toNum(order?.price, null);
  if (pOrder != null && pOrder > 0) return { price: pOrder, source: "order.price" };
  const pCtx = toNum(prices?.[symbol]?.lastPrice, null);
  if (pCtx != null && pCtx > 0) return { price: pCtx, source: "market.lastPrice" };
  const pLimit = toNum(order?.limitPrice, null);
  if (pLimit != null && pLimit > 0) return { price: pLimit, source: "order.limitPrice" };
  return { price: null, source: "missing" };
}

function buildSymbolRegex() {
  return /\b[A-Z0-9]{1,10}(?:\.[A-Z]{1,4})?\b/g;
}

const input = $json || {};
const ctx = input.ctx || {};
const runCtx = ctx.run || {};
const market = ctx.market || {};
const prices = isObj(market.prices) ? market.prices : {};
const dataQuality = isObj(market.dataQuality) ? market.dataQuality : {};
const nowIso = new Date().toISOString();
const n8nExecutionId =
  typeof $execution !== "undefined" && $execution && $execution.id != null
    ? clampText($execution.id, 128)
    : null;

const agentDecision = parseAgentDecision(input);
const actions = Array.isArray(agentDecision.actions) ? agentDecision.actions : [];
const ordersIn = Array.isArray(input.orders) ? input.orders : [];
const warnings = Array.isArray(input.warnings) ? input.warnings.map((x) => String(x)) : [];
const hasSafetyVeto = warnings.some((w) => String(w).startsWith("SAFETY_VETO_"));
const decision = clampText(input.decision, 32) || "NO_TRADE";
const commentary = clampText(input.commentary, 600);

const run_id = buildRunId(runCtx, agentDecision, nowIso, n8nExecutionId);
const ts_start = clampText(runCtx.timestampParis, 64) || nowIso;
const ts_end = nowIso;

const config = isObj(ctx.config) ? ctx.config : {};
const feesConfig = isObj(ctx.feesConfig) ? ctx.feesConfig : {};
const fixedFee = Math.max(0, toNum(feesConfig.orderFeeFixedEUR, 0));
const pctFee = Math.max(0, toNum(feesConfig.orderFeePct, 0));

const strategyVersion =
  clampText(config.strategyVersion, 64) ||
  clampText(agentDecision?.decisionMeta?.strategy_version, 64) ||
  "strategy_v3";
const configVersion = clampText(config.configVersion, 64) || "config_v3";
const promptVersion =
  clampText(runCtx.promptVersion, 64) ||
  clampText(agentDecision?.decisionMeta?.prompt_version, 64) ||
  "prompt_v3";
const model =
  clampText(runCtx.model, 64) ||
  clampText(agentDecision?.decisionMeta?.model, 64) ||
  "gpt-5.2";

const coveragePct = normPctTo100(dataQuality?.pricesCoverageRequested);
const newsCount = Array.isArray(market.newsItems) ? market.newsItems.length : 0;
const aiCost = Math.max(0, toNum(input?.metrics?.aiCostEUR, 0));
const expectedFees = Math.max(0, toNum(input?.metrics?.expectedFeesEUR, 0));
const dataOkForTrading = !!(dataQuality?.okForTrading ?? !hasSafetyVeto);

const run = {
  run_id,
  ts_start,
  ts_end,
  tz: "Europe/Paris",
  strategy_version: strategyVersion,
  config_version: configVersion,
  prompt_version: promptVersion,
  model,
  n8n_execution_id: n8nExecutionId || null,
  decision_summary: `${decision} | orders=${ordersIn.length}`,
  data_ok_for_trading: dataOkForTrading,
  price_coverage_pct: coveragePct,
  news_count: newsCount,
  ai_cost_eur: aiCost,
  expected_fees_eur: expectedFees,
  warnings_json: warnings,
  agent_output_json: agentDecision,
  risk_gate_json: {
    ok_for_trading: dataOkForTrading,
    data_quality: dataQuality,
    decision,
    input_snapshot: runCtx.inputSnapshot || null,
    universe_scope: runCtx.universe_scope || ["EQUITY", "CRYPTO"],
    enable_fx: runCtx.enable_fx === true,
  },
};

const actionBySymbol = getOrderActionMap(actions);

const orders = [];
const fills = [];
const cash_ledger = [];
const alerts = [];
const ai_signals = [];
const market_prices = [];

for (let i = 0; i < ordersIn.length; i++) {
  const o = ordersIn[i] || {};
  const symbol = normSymbol(o.symbol);
  const side = clampText(o.side, 8).toUpperCase();
  const qty = toNum(o.quantity, null);
  if (!symbol || !["BUY", "SELL"].includes(side) || qty == null || qty <= 0) continue;

  const action = actionBySymbol.get(symbol) || "";
  const order_id = makeId("ORD", run_id, String(i + 1).padStart(3, "0"), symbol, side);
  const order_type = clampText(o.orderType, 16).toUpperCase() || "MARKET";

  const baseOrder = {
    order_id,
    run_id,
    ts_created: ts_end,
    symbol,
    side,
    intent: mapIntent(action, side),
    order_type,
    qty,
    limit_price: toNum(o.limitPrice, null),
    stop_price: toNum(o.stopPrice, null),
    tif: clampText(o.timeInForce, 8) || "DAY",
    status: "PLANNED",
    broker: clampText(o.broker, 24) || "SIM",
    reason: clampText(o.reason, 160) || null,
    rationale_json: {
      confidence: clamp0100(o.confidence),
      priority: toInt(o.priority, null),
      stop_loss_pct: toNum(o.stopLossPct, null),
      rationale: clampText(o.rationale, 600),
      action,
    },
  };

  const px = extractPrice(symbol, o, prices);
  if (px.price == null || px.price <= 0) {
    baseOrder.status = "SKIPPED";
    baseOrder.reason = baseOrder.reason || "NO_EXEC_PRICE";
    orders.push(baseOrder);
    alerts.push({
      alert_id: makeId("ALT", run_id, "NO_PRICE", symbol, String(i + 1)),
      run_id,
      ts: ts_end,
      severity: "WARN",
      category: "EXECUTION",
      symbol,
      message: `Order skipped: no execution price for ${symbol}`,
      code: "ORDER_SKIPPED_NO_PRICE",
      payload_json: { order_id },
    });
    continue;
  }

  baseOrder.status = "FILLED";
  orders.push(baseOrder);

  const fill_id = makeId("FIL", order_id, "1");
  const notional = qty * px.price;
  const fees_eur = fixedFee + pctFee * notional;

  fills.push({
    fill_id,
    order_id,
    run_id,
    ts_fill: ts_end,
    qty,
    price: px.price,
    fees_eur,
    slippage_bps: 0,
    liquidity: "UNKNOWN",
    raw_fill_json: {
      mode: "SIM",
      price_source: px.source,
      decision,
    },
  });

  cash_ledger.push({
    cash_tx_id: makeId("TX", run_id, fill_id, "NOTIONAL"),
    run_id,
    ts: ts_end,
    currency: "EUR",
    amount: side === "BUY" ? -notional : notional,
    type: "TRADE_NOTIONAL",
    symbol,
    ref_id: fill_id,
    notes: `${side} ${qty} ${symbol} @ ${px.price}`,
    payload_json: { order_id, fill_id },
  });

  if (fees_eur > 0) {
    cash_ledger.push({
      cash_tx_id: makeId("TX", run_id, fill_id, "FEE"),
      run_id,
      ts: ts_end,
      currency: "EUR",
      amount: -fees_eur,
      type: "FEE",
      symbol,
      ref_id: fill_id,
      notes: `Execution fee ${symbol}`,
      payload_json: { order_id, fill_id },
    });
  }
}

if (aiCost > 0) {
  cash_ledger.push({
    cash_tx_id: makeId("TX", run_id, "AI_COST"),
    run_id,
    ts: ts_end,
    currency: "EUR",
    amount: -aiCost,
    type: "AI_COST",
    symbol: null,
    ref_id: run_id,
    notes: "LLM cost for run",
    payload_json: { model, promptVersion },
  });
}

for (let i = 0; i < actions.length; i++) {
  const a = actions[i] || {};
  const isFx = String(a.assetClass || "").toUpperCase() === "FX" || String(a.symbol || "").toUpperCase().startsWith("FX:");
  const symbol = normSymbol((isFx ? (a.symbol_internal || a.symbol) : a.symbol));
  if (!symbol) continue;
  const entryPlan = isObj(a.entryPlan) ? a.entryPlan : {};
  const riskPlan = isObj(a.riskPlan) ? a.riskPlan : {};
  const confidence = clamp0100(a.confidence);
  ai_signals.push({
    signal_id: makeId("SIG", run_id, String(i + 1).padStart(3, "0"), symbol),
    run_id,
    ts: ts_end,
    symbol,
    signal: mapSignal(a.action),
    confidence,
    horizon: clampText(a.horizon || "", 24) || (toInt(a.horizonDays, null) ? `D${toInt(a.horizonDays, 0)}` : null),
    entry_zone: clampText(entryPlan.entryZone || "", 120) || null,
    stop_loss: toNum(entryPlan.stopLoss ?? riskPlan.stopLoss ?? riskPlan.stopLossPct, null),
    take_profit: toNum(entryPlan.takeProfit ?? riskPlan.takeProfit ?? riskPlan.takeProfitPct, null),
    risk_score: confidence == null ? null : 100 - confidence,
    catalyst: clampText(a.catalyst || "", 240) || null,
    rationale: clampText(a.rationale || "", 800) || null,
    payload_json: a,
  });
}

for (const [sym, p] of Object.entries(prices)) {
  const symbol = normSymbol(sym);
  if (!symbol) continue;
  market_prices.push({
    ts: ts_end,
    symbol,
    open: toNum(p?.open, null),
    high: toNum(p?.high, null),
    low: toNum(p?.low, null),
    close: toNum(p?.lastPrice ?? p?.close, null),
    adj_close: toNum(p?.adjClose, null),
    volume: toInt(p?.volume, null),
    source: clampText(p?.source, 32) || "YF",
    asof: clampText(p?.ts, 64) || ts_end,
  });
}

const symbolRegex = buildSymbolRegex();
if (!dataOkForTrading) {
  alerts.push({
    alert_id: makeId("ALT", run_id, "DATA_GATE"),
    run_id,
    ts: ts_end,
    severity: "CRITICAL",
    category: "DATA",
    symbol: "GLOBAL",
    message: "Market data safety gate failed",
    code: "DATA_GATE_FAIL",
    payload_json: dataQuality,
  });
}

for (let i = 0; i < warnings.length; i++) {
  const w = warnings[i];
  const m = w.match(symbolRegex);
  alerts.push({
    alert_id: makeId("ALT", run_id, "WARN", String(i + 1).padStart(3, "0")),
    run_id,
    ts: ts_end,
    severity: "WARN",
    category: "AGENT",
    symbol: (m && m[0]) || "GLOBAL",
    message: clampText(w, 2048),
    code: "AGENT_WARNING",
    payload_json: { warning: w },
  });
}

const backfill_queue = [];
const backfills = Array.isArray(agentDecision.backfillRequests) ? agentDecision.backfillRequests : [];
for (const bf of backfills) {
  const symbol = normSymbol(bf?.symbol);
  const needsArr = Array.isArray(bf?.needs) ? uniq(bf.needs.map((x) => clampText(x, 24)).filter(Boolean)) : [];
  if (!symbol || !needsArr.length) continue;
  const needsCsv = needsArr.join(",");
  backfill_queue.push({
    request_id: makeId("BF", symbol, needsCsv),
    run_id,
    ts: ts_end,
    symbol,
    needs: needsCsv,
    severity: "MEDIUM",
    status: "OPEN",
    why: clampText(bf?.why, 700) || null,
    completed_at: null,
    response_json: null,
    notes: null,
  });
}

const positions = Array.isArray(ctx?.portfolioSummary?.positions) ? ctx.portfolioSummary.positions : [];
const symbolsFromPositions = positions
  .map((p) => normSymbol(p.Symbol ?? p.symbol))
  .filter((s) => s && s !== "CASH_EUR" && s !== "__META__");
const symbolsAll = uniq([
  ...symbolsFromPositions,
  ...orders.map((o) => o.symbol),
  ...ai_signals.map((s) => s.symbol),
  ...market_prices.map((m) => m.symbol),
  ...backfill_queue.map((b) => b.symbol),
]);

const instruments = symbolsAll.map((symbol) => {
  const p = positions.find((x) => normSymbol(x.Symbol ?? x.symbol) === symbol) || {};
  const inferredFx = String(symbol || "").toUpperCase().startsWith("FX:");
  return {
    symbol,
    name: clampText(p.Name ?? p.name, 240) || null,
    asset_class: clampText(p.AssetClass ?? p.assetClass, 64) || (inferredFx ? "FX" : "Equity"),
    currency: "EUR",
    isin: clampText(p.ISIN ?? p.isin, 64) || null,
    sector: clampText(p.Sector ?? p.sector, 120) || null,
    industry: clampText(p.Industry ?? p.industry, 120) || null,
  };
});

const bundle = {
  run,
  instruments,
  orders,
  fills,
  cash_ledger,
  ai_signals,
  market_prices,
  alerts,
  backfill_queue,
  snapshots: {},
};

const db_path =
  clampText(input?.db_path, 240) ||
  clampText(ctx?.db_path, 240) ||
  clampText(config?.ag1DbPath, 240) ||
  "/files/duckdb/ag1_v3.duckdb";

return [
  {
    json: {
      run_id,
      db_path,
      bundle,
      summary: {
        decision,
        commentary,
        orders: orders.length,
        fills: fills.length,
        cash_ledger: cash_ledger.length,
        alerts: alerts.length,
        backfill: backfill_queue.length,
        ai_signals: ai_signals.length,
      },
    },
  },
];

// 2B - Init Run Context
// Code node (typeVersion 2)
// Output: enrichit la config avec run { runId, timestampParis, timestampUtc, tz, executionId, versions }

const cfg = $json ?? {};
const tz = String(cfg.timezone || "Europe/Paris");

const now = new Date();

const pad2 = (n) => String(n).padStart(2, "0");

// Construit un "local ISO" en timezone Europe/Paris via Intl (sans librairie externe)
const partsToObj = (parts) =>
  parts
    .filter((p) => p.type !== "literal")
    .reduce((acc, p) => ((acc[p.type] = p.value), acc), {});

const dtf = new Intl.DateTimeFormat("en-GB", {
  timeZone: tz,
  hour12: false,
  year: "numeric",
  month: "2-digit",
  day: "2-digit",
  hour: "2-digit",
  minute: "2-digit",
  second: "2-digit",
});

const parts = partsToObj(dtf.formatToParts(now));
const isoLocal = `${parts.year}-${parts.month}-${parts.day}T${parts.hour}:${parts.minute}:${parts.second}`;

// Calcule l’offset (minutes) entre UTC et Europe/Paris à cet instant
// Astuce : on interprète l'heure "Paris" comme UTC, et on compare à l'instant réel.
const msLocalAsUtc = Date.parse(`${isoLocal}Z`);
const offsetMin = Math.round((msLocalAsUtc - now.getTime()) / 60000);
const sign = offsetMin >= 0 ? "+" : "-";
const abs = Math.abs(offsetMin);
const offsetStr = `${sign}${pad2(Math.floor(abs / 60))}:${pad2(abs % 60)}`;

const timestampParis = `${isoLocal}${offsetStr}`;
const timestampUtc = now.toISOString();

const executionId = cfg.execution_id ? String(cfg.execution_id) : null;
const enableFxRaw = cfg.enable_fx ?? cfg.ENABLE_FX ?? false;
const enableFx =
  typeof enableFxRaw === "boolean"
    ? enableFxRaw
    : ["1", "true", "yes", "y", "on", "enabled"].includes(String(enableFxRaw || "").trim().toLowerCase());
const universeScope = ["EQUITY", "CRYPTO"];
if (enableFx) universeScope.push("FX");

// run_id: RUN_YYYYMMDD_HHMMSS_<executionId|rand>
const yyyymmdd = `${parts.year}${parts.month}${parts.day}`;
const hhmmss = `${parts.hour}${parts.minute}${parts.second}`;
const rand = Math.random().toString(16).slice(2, 10) + Math.random().toString(16).slice(2, 10);
const runId = `RUN_${yyyymmdd}_${hhmmss}_${executionId ?? rand}`;

return [
  {
    json: {
      ...cfg,
      run: {
        runId,
        timestampParis,
        timestampUtc,
        tz,
        offsetMin,
        executionId,
        strategyVersion: String(cfg.strategy_version || "strategy_v3"),
        configVersion: String(cfg.config_version || "config_v3"),
        promptVersion: String(cfg.prompt_version || "prompt_v3"),
        model: String(cfg.model || "gpt-5.2"),
        enable_fx: enableFx,
        universe_scope: universeScope,
        inputSnapshot: {
          universe_scope: universeScope,
        },
      },
    },
  },
];

