import os
import gc
import time
import duckdb
from contextlib import contextmanager
from datetime import datetime, timezone

DB_PATH_DEFAULT = os.getenv("AG1_DUCKDB_PATH", "/files/duckdb/ag1_v3.duckdb")


def to_num(v, default=0.0):
    try:
        if v is None or v == "":
            return default
        s = str(v).replace("EUR", "").replace("€", "").replace("\u00a0", "").replace("\u202f", "").replace(" ", "").replace(",", ".")
        n = float(s)
        return n if n == n else default
    except Exception:
        return default


def round2(v):
    return round(float(v or 0.0), 2)


def norm_text(v):
    return str(v or "").strip().upper()


def is_cash_row(r):
    sym = norm_text(r.get("Symbol") or r.get("symbol"))
    name = norm_text(r.get("Name") or r.get("name"))
    asset = norm_text(r.get("AssetClass") or r.get("assetClass") or r.get("asset_class"))
    sector = norm_text(r.get("Sector") or r.get("sector"))
    return (
        sym in ("CASH_EUR", "CASH", "EUR_CASH", "LIQUIDITE", "LIQUIDITES")
        or "CASH" in name
        or "LIQUIDITE" in name
        or asset == "CASH"
        or sector == "CASH"
    )


def is_meta_row(r):
    sym = norm_text(r.get("Symbol") or r.get("symbol"))
    name = norm_text(r.get("Name") or r.get("name"))
    return sym == "__META__" or name == "__META__"


@contextmanager
def db_con(path, retries=5, delay=0.25):
    con = None
    for i in range(retries):
        try:
            con = duckdb.connect(path, read_only=True)
            break
        except Exception as e:
            if ("lock" in str(e).lower() or "busy" in str(e).lower()) and i < retries - 1:
                time.sleep(delay * (2 ** i))
            else:
                con = None
                break
    try:
        yield con
    finally:
        if con is not None:
            try:
                con.close()
            except Exception:
                pass
        gc.collect()


def load_rows_from_duckdb(db_path):
    with db_con(db_path) as con:
        if con is None:
            return []
        try:
            cur = con.execute(
                """
                SELECT
                  symbol,
                  name,
                  asset_class,
                  sector,
                  industry,
                  quantity,
                  last_price,
                  market_value,
